// Dans l'écran de détail, bouton Modifier
onPressed: () async {
  final updated = await Navigator.push(context, MaterialPageRoute(builder: (context) => EditRecipeScreen(recipe: currentRecipe)));
  if (updated != null) {
    setState(() {
      int index = recipes.indexWhere((r) => r.id == currentRecipe.id);
      recipes[index] = updated;
    });
  }
}
